/* eslint-disable no-invalid-this */
/* eslint-disable max-len */
import {
	jsPDF,
} from 'jspdf'
const font = ''
type JsPDFAPI = {
	addFileToVFS: (fontName: string, font: string) => void;
	addFont: (fontName: string, fontFamily: string, fontStyle: string) => void;
};
const callAddFont = function(this: JsPDFAPI,): void {
	this.addFileToVFS('Montserrat-Medium-normal.ttf', font,)
	this.addFont('Montserrat-Medium-normal.ttf', 'Montserrat', 'normal',)
	// this.addFont('serif', 'serif', 'normal',)
}
export function addFontMedium(): void {
	jsPDF.API.events.push(['addFonts', callAddFont,],)
}